  1→import { useCallback, useId, useRef } from 'react';
  2→import { FormField } from './form_field';
  3→import './form_file_picker.scss';
  4→
  5→export interface FilePickerFile {
  6→  name: string;
  7→  size: number;
  8→  type: string;
  9→}
 10→
 11→interface FormFilePickerProps {
 12→  label: string;
 13→  value: FilePickerFile[];
 14→  onChange: (files: FilePickerFile[]) => void;
 15→  allowMultiple?: boolean;
 16→  accept?: string;
 17→  description?: string;
 18→  error?: string;
 19→}
 20→
 21→function formatFileSize(bytes: number): string {
 22→  if (bytes < 1024) return `${bytes} B`;
 23→  if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
 24→  return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
 25→}
 26→
 27→export function FormFilePicker({
 28→  label,
 29→  value,
 30→  onChange,
 31→  allowMultiple = false,
 32→  accept,
 33→  description,
 34→  error,
 35→}: FormFilePickerProps) {
 36→  const id = useId();
 37→  const inputRef = useRef<HTMLInputElement>(null);
 38→
 39→  const handleChange = useCallback(
 40→    (e: React.ChangeEvent<HTMLInputElement>) => {
 41→      const fileList = e.target.files;
 42→      if (!fileList || fileList.length === 0) return;
 43→
 44→      const picked: FilePickerFile[] = Array.from(fileList).map(f => ({
 45→        name: f.name,
 46→        size: f.size,
 47→        type: f.type,
 48→      }));
 49→
 50→      if (allowMultiple) {
 51→        onChange([
 52→          ...value,
 53→          ...picked,
 54→        ]);
 55→      } else {
 56→        onChange(picked.slice(0, 1));
 57→      }
 58→
 59→      e.target.value = '';
 60→    },
 61→    [
 62→      value,
 63→      onChange,
 64→      allowMultiple,
 65→    ],
 66→  );
 67→
 68→  const removeFile = useCallback(
 69→    (index: number) => {
 70→      onChange(value.filter((_, i) => i !== index));
 71→    },
 72→    [
 73→      value,
 74→      onChange,
 75→    ],
 76→  );
 77→
 78→  const handleBrowseClick = useCallback(() => {
 79→    inputRef.current?.click();
 80→  }, []);
 81→
 82→  const handleKeyDown = useCallback((e: React.KeyboardEvent) => {
 83→    if (e.key === 'Enter' || e.key === ' ') {
 84→      e.preventDefault();
 85→      inputRef.current?.click();
 86→    }
 87→  }, []);
 88→
 89→  return (
 90→    <FormField
 91→      label={label}
 92→      description={description}
 93→      error={error}
 94→      htmlFor={id}
 95→    >
 96→      <div className="form-file-picker">
 97→        <input
 98→          id={id}
 99→          ref={inputRef}
100→          className="form-file-picker__native-input"
101→          type="file"
102→          multiple={allowMultiple}
103→          accept={accept}
104→          onChange={handleChange}
105→          aria-invalid={error ? true : undefined}
106→          aria-describedby={error ? `${id}-error` : undefined}
107→          tabIndex={-1}
108→        />
109→        {value.length > 0 && (
110→          <div className="form-file-picker__files">
111→            {value.map((file, i) => (
112→              <span
113→                key={`${file.name}-${i}`}
114→                className="form-file-picker__pill"
115→              >
116→                <svg
117→                  className="form-file-picker__pill-icon"
118→                  width="12"
119→                  height="12"
120→                  viewBox="0 0 16 16"
121→                  fill="none"
122→                >
123→                  <path
124→                    d="M4 1.5h5.586a1 1 0 0 1 .707.293l2.414 2.414a1 1 0 0 1 .293.707V13.5a1 1 0 0 1-1 1H4a1 1 0 0 1-1-1v-11a1 1 0 0 1 1-1Z"
125→                    stroke="currentColor"
126→                    strokeWidth="1.25"
127→                  />
128→                  <path
129→                    d="M9.5 1.5V4a.5.5 0 0 0 .5.5h2.5"
130→                    stroke="currentColor"
131→                    strokeWidth="1.25"
132→                    strokeLinecap="round"
133→                    strokeLinejoin="round"
134→                  />
135→                </svg>
136→                <span className="form-file-picker__pill-name">{file.name}</span>
137→                <span className="form-file-picker__pill-size">
138→                  {formatFileSize(file.size)}
139→                </span>
140→                <button
141→                  type="button"
142→                  className="form-file-picker__pill-remove"
143→                  onClick={() => removeFile(i)}
144→                  aria-label={`Remove ${file.name}`}
145→                >
146→                  <svg width="8" height="8" viewBox="0 0 8 8" fill="none">
147→                    <path
148→                      d="M1 1L7 7M7 1L1 7"
149→                      stroke="currentColor"
150→                      strokeWidth="1.5"
151→                      strokeLinecap="round"
152→                    />
153→                  </svg>
154→                </button>
155→              </span>
156→            ))}
157→          </div>
158→        )}
159→        <button
160→          type="button"
161→          className="form-file-picker__browse"
162→          onClick={handleBrowseClick}
163→          onKeyDown={handleKeyDown}
164→        >
165→          <svg width="14" height="14" viewBox="0 0 16 16" fill="none">
166→            <path
167→              d="M8 3v10M3 8h10"
168→              stroke="currentColor"
169→              strokeWidth="1.5"
170→              strokeLinecap="round"
171→            />
172→          </svg>
173→          {value.length === 0
174→            ? 'Choose File'
175→            : allowMultiple
176→              ? 'Add More'
177→              : 'Replace File'}
178→        </button>
179→      </div>
180→    </FormField>
181→  );
182→}
